import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import '../styles/register.css';

export const Register = () => {
  const [formData, setFormData] = useState({
    fullName: '',
    username: '',
    email: '',
    farmName: '',
    password: '',
    passwordConfirm: '',
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [showPasswordConfirm, setShowPasswordConfirm] = useState(false);

  const { register } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const validateForm = () => {
    if (!formData.fullName || !formData.username || !formData.email || !formData.farmName || !formData.password || !formData.passwordConfirm) {
      setError('Vui lòng điền đầy đủ thông tin');
      return false;
    }

    if (formData.password.length < 6) {
      setError('Mật khẩu phải có ít nhất 6 ký tự');
      return false;
    }

    if (formData.password !== formData.passwordConfirm) {
      setError('Mật khẩu không khớp');
      return false;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      setError('Email không hợp lệ');
      return false;
    }

    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    if (!validateForm()) {
      setLoading(false);
      return;
    }

    const result = await register(
      formData.fullName,
      formData.username,
      formData.email,
      formData.password,
      formData.passwordConfirm,
      formData.farmName
    );
    setLoading(false);

    if (result.success) {
      // Redirect đến dashboard dựa trên role
      const role = result.user?.role;
      if (role === 'ADMIN') {
        navigate('/admin/dashboard');
      } else if (role === 'OWNER') {
        navigate('/owner/dashboard');
      } else if (role === 'MANAGER') {
        navigate('/manager/dashboard');
      } else if (role === 'WORKER') {
        navigate('/worker/dashboard');
      } else if (role === 'TECHNICIAN') {
        navigate('/technician/dashboard');
      } else if (role === 'ACCOUNTANT') {
        navigate('/accountant/dashboard');
      } else if (role === 'STOREKEEPER') {
        navigate('/storekeeper/dashboard');
      } else {
        navigate('/');
      }
    } else {
      setError(result.message);
    }
  };

  return (
    <div className="register-page">
      <div className="register-card">
        <div className="register-brand">
          <div className="register-brand__icon">🦐</div>
        </div>

        <form onSubmit={handleSubmit} className="register-form">
          <h1 className="register-form__title">Đăng ký</h1>
          <p className="register-form__subtitle">Tạo tài khoản để quản lý ao tôm thông minh</p>

          {error && <div className="register-alert register-alert--error">{error}</div>}

          <div className="register-field">
            <label htmlFor="fullName" className="register-field__label">Họ và tên</label>
            <div className="field-shell field-shell--text">
              <span className="field-shell__icon">👤</span>
              <input
                id="fullName"
                className="field-shell__input"
                type="text"
                name="fullName"
                placeholder="Nhập họ và tên"
                value={formData.fullName}
                onChange={handleChange}
                disabled={loading}
                required
              />
            </div>
          </div>

          <div className="register-field">
            <label htmlFor="username" className="register-field__label">Tên đăng nhập</label>
            <div className="field-shell field-shell--text">
              <span className="field-shell__icon">👤</span>
              <input
                id="username"
                className="field-shell__input"
                type="text"
                name="username"
                placeholder="Nhập tên đăng nhập"
                value={formData.username}
                onChange={handleChange}
                disabled={loading}
                required
              />
            </div>
          </div>

          <div className="register-field">
            <label htmlFor="email" className="register-field__label">Email</label>
            <div className="field-shell field-shell--text">
              <span className="field-shell__icon">📧</span>
              <input
                id="email"
                className="field-shell__input"
                type="email"
                name="email"
                placeholder="Nhập email"
                value={formData.email}
                onChange={handleChange}
                disabled={loading}
                required
              />
            </div>
          </div>

          <div className="register-field">
            <label htmlFor="farmName" className="register-field__label">Tên trại nuôi</label>
            <div className="field-shell field-shell--text">
              <span className="field-shell__icon">🏭</span>
              <input
                id="farmName"
                className="field-shell__input"
                type="text"
                name="farmName"
                placeholder="Nhập tên trại nuôi"
                value={formData.farmName}
                onChange={handleChange}
                disabled={loading}
                required
              />
            </div>
          </div>

          <div className="register-field">
            <label htmlFor="password" className="register-field__label">Mật khẩu</label>
            <div className="field-shell field-shell--password">
              <span className="field-shell__icon">🔒</span>
              <input
                id="password"
                className="field-shell__input"
                type={showPassword ? 'text' : 'password'}
                name="password"
                placeholder="Nhập mật khẩu (tối thiểu 6 ký tự)"
                value={formData.password}
                onChange={handleChange}
                disabled={loading}
                required
              />
              <button
                type="button"
                className="field-shell__toggle"
                onClick={() => setShowPassword(!showPassword)}
                tabIndex="-1"
                aria-label={showPassword ? 'Ẩn mật khẩu' : 'Hiện mật khẩu'}
              >
                {showPassword ? '🙈' : '👁️'}
              </button>
            </div>
          </div>

          <div className="register-field">
            <label htmlFor="passwordConfirm" className="register-field__label">Xác nhận mật khẩu</label>
            <div className="field-shell field-shell--password">
              <span className="field-shell__icon">🔒</span>
              <input
                id="passwordConfirm"
                className="field-shell__input"
                type={showPasswordConfirm ? 'text' : 'password'}
                name="passwordConfirm"
                placeholder="Xác nhận mật khẩu"
                value={formData.passwordConfirm}
                onChange={handleChange}
                disabled={loading}
                required
              />
              <button
                type="button"
                className="field-shell__toggle"
                onClick={() => setShowPasswordConfirm(!showPasswordConfirm)}
                tabIndex="-1"
                aria-label={showPasswordConfirm ? 'Ẩn xác nhận mật khẩu' : 'Hiện xác nhận mật khẩu'}
              >
                {showPasswordConfirm ? '🙈' : '👁️'}
              </button>
            </div>
          </div>

          <button type="submit" className="register-button" disabled={loading}>
            {loading ? 'Đang đăng ký...' : 'Đăng ký'}
          </button>
        </form>

        <div className="register-footer">
          <p>
            Đã có tài khoản?{' '}
            <Link to="/login" className="register-footer__link">
              Đăng nhập ngay
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default Register;
